patch:
===== uhci-hcd.c 1.78 vs edited =====
--- 1.78/drivers/usb/host/uhci-hcd.c	Thu Feb  5 05:59:31 2004
+++ edited/drivers/usb/host/uhci-hcd.c	Mon Feb  9 11:02:33 2004
@@ -1516,6 +1516,7 @@
 	}

 	spin_unlock_irqrestore(&uhci->urb_list_lock, flags);
+	printk(KERN_DEBUG "%lx: queue urb %p\n", uhci->io_addr, urb);

 	return 0;
 }
@@ -1667,6 +1668,7 @@
 	  return 0;
 	}

+	printk(KERN_DEBUG "%lx: dequeue urb %p\n", uhci->io_addr, urb);
 	spin_lock_irqsave(&uhci->urb_list_lock, flags);

 	list_del_init(&urbp->urb_list);
@@ -1857,6 +1859,7 @@
 		urb->status = status;
 	spin_unlock_irqrestore(&urb->lock, flags);

+	printk(KERN_DEBUG "%lx: giveback urb %p\n", uhci->io_addr, urb);
 	usb_hcd_giveback_urb(hcd, urb, regs);
 }

@@ -1923,6 +1926,7 @@
 	if (!status)	/* shared interrupt, not mine */
 		return IRQ_NONE;
 	outw(status, io_addr + USBSTS);		/* Clear it */
+	printk(KERN_DEBUG "%x: irq status 0x%x\n", io_addr, status);

 	if (status & ~(USBSTS_USBINT | USBSTS_ERROR | USBSTS_RD)) {
 		if (status & USBSTS_HSE)
